const e="ITR-5",t="2025-26",i=[{id:"RF-ITR5-01",category:"partner-remuneration",severity:"critical",title:"Partner Remuneration Exceeds Section 40(b) Limits",description:"Remuneration paid to working partners exceeds the limits prescribed u/s 40(b): 90% of first ₹3L of book profit + 60% of balance. Excess is disallowed.",consequence:"Excess remuneration added back to firm income, increasing tax liability.",correction:"Cap actual remuneration payments within 40(b) limits before filing.",legalReference:"Section 40(b), Income-tax Act 1961"},{id:"RF-ITR5-02",category:"partner-interest",severity:"critical",title:"Interest to Partners Above 12% Per Annum",description:"Section 40(b) caps partner interest at 12% per annum on capital contribution. Any excess is disallowed.",consequence:"Disallowance increases firm's taxable income.",correction:"Restrict interest rate in partnership deed to maximum 12% per annum. Recompute and add back excess interest.",legalReference:"Section 40(b), Income-tax Act 1961"},{id:"RF-ITR5-03",category:"tax-audit",severity:"critical",title:"Tax Audit Not Filed When Turnover Exceeds ₹1 Crore",description:"Firms with total turnover or gross receipts > ₹1 Crore must get accounts audited u/s 44AB. Audit report (Form 3CA + 3CD) must be filed electronically before filing ITR-5.",consequence:"Penalty u/s 271B: 0.5% of turnover or ₹1.5L, whichever is lower.",correction:"Engage a CA to conduct tax audit and file Form 3CA/3CD before the ITR-5 due date.",legalReference:"Section 44AB, Income-tax Act"},{id:"RF-ITR5-04",category:"gst-mismatch",severity:"high",title:"GST Turnover Mismatch with ITR-5 Business Income",description:"GSTN shares data with Income Tax department. Turnover in GSTR-9 vs ITR-5 Schedule BP difference triggers AI-flagged notices.",consequence:"Scrutiny assessment notice. Must reconcile or explain difference with valid reasons (e.g., exempt supplies, composition scheme).",correction:"Reconcile GSTR-1/GSTR-3B/GSTR-9 turnover with ITR-5 business income before filing. Prepare reconciliation statement.",legalReference:"Section 143(1)(a) — mismatch processing"},{id:"RF-ITR5-05",category:"income-computation",severity:"high",title:"Deducting Partner's Share of Profit from Firm Income",description:"Partners' share of profit in a firm is not deductible from firm's income. Only remuneration u/s 40(b) and interest u/s 40(b) are deductible. The firm pays tax on its whole profit after these deductions.",consequence:"Return treated as defective; income understated.",correction:"Do not deduct partners' profit share while computing firm's taxable income. Only deduct remuneration and interest within 40(b) limits.",legalReference:"Section 10(2A), Section 40(b)"},{id:"RF-ITR5-06",category:"mat-inapplicable",severity:"high",title:"LLP Claiming MAT Provisions",description:"MAT u/s 115JB applies only to companies. LLPs are NOT subject to MAT. Applying MAT to LLP leads to incorrect and potentially higher tax computation.",consequence:"Incorrect tax computation. May result in overpayment or trigger mismatch if MAT figures appear in non-company return.",correction:"Remove MAT computation. LLPs pay tax at flat 30% on taxable income.",legalReference:"Section 115JB (applies only to companies)"},{id:"RF-ITR5-07",category:"wrong-form",severity:"high",title:"Filing ITR-5 for a Charitable Trust",description:"Charitable trusts registered u/s 12A/12AB should file ITR-7 to claim exemption u/s 11/12. Filing ITR-5 means no exemption claimed and full income taxed.",consequence:"Loss of charitable exemption. Excess tax payment.",correction:"Switch to ITR-7. Ensure trust has valid 12A/12AB registration. Claim exemption u/s 11 in ITR-7.",legalReference:"Section 139(4A), Section 11, Section 12A/12AB"},{id:"RF-ITR5-08",category:"cash-payment-disallowance",severity:"medium",title:"Cash Payments Above ₹10,000 Claimed as Deduction",description:"Section 40A(3) disallows expense if payment to a single person in a day exceeds ₹10,000 in cash. Must add back to income.",consequence:"Disallowance of cash payments increases taxable income of firm.",correction:"Make payments above ₹10,000 through banking channels (cheque, NEFT, RTGS, UPI). Review cash payment register before filing.",legalReference:"Section 40A(3), Income-tax Act"},{id:"RF-ITR5-09",category:"tds-default",severity:"medium",title:"TDS Default on Contractor Payments (Section 194C)",description:"If firm pays contractors > ₹30K per transaction or ₹1L per year without deducting TDS u/s 194C, 30% of such payment is disallowed u/s 40(a)(ia).",consequence:"30% disallowance of contractor payments not covered by TDS increases taxable income.",correction:"Deduct TDS u/s 194C at 1% (individual/HUF) or 2% (others) on contractor payments exceeding threshold. File TDS returns timely.",legalReference:"Section 40(a)(ia)"},{id:"RF-ITR5-10",category:"late-filing",severity:"medium",title:"Not Carrying Forward Business Loss Due to Late Filing",description:"Business losses can be carried forward for 8 years only if return is filed by due date (July 31 for non-audit firms; October 31 for audit firms). Late filing forfeits loss carry-forward.",consequence:"Permanent loss of ability to carry forward business losses. Future tax benefit lost.",correction:"File ITR-5 by the due date even if tax payable is nil. Loss carry-forward is a valuable future asset.",legalReference:"Section 139(3)"}],r=[{errorCode:"ITR5-VE-01",errorMessage:"Remuneration to partners exceeds Section 40(b) limit",cause:"Excess remuneration paid to working partners beyond statutory formula",resolution:"Reduce remuneration to the 40(b) permitted amount: 90% of first ₹3L book profit + 60% of balance. Add back excess in Schedule BP."},{errorCode:"ITR5-VE-02",errorMessage:"Tax audit report not attached when mandatory",cause:"Firm turnover exceeds ₹1 Crore but Form 3CA/3CD audit report not uploaded",resolution:"File Form 3CA/3CD audit report through CA login on Income Tax portal before submitting ITR-5."},{errorCode:"ITR5-VE-03",errorMessage:"Interest to partners exceeds 12% per annum",cause:"Partnership deed specifies higher interest rate than 12% per annum on capital",resolution:"Restrict interest deduction to maximum 12% per annum in Schedule BP. Add back excess interest paid."},{errorCode:"ITR5-VE-04",errorMessage:"Partnership deed not executed or not registered",cause:"No valid written and registered partnership deed in place",resolution:"Execute and register partnership deed with the sub-registrar. Without valid deed, 40(b) deductions for remuneration and interest are not available."},{errorCode:"ITR5-VE-05",errorMessage:"AMT u/s 115JC not computed when deductions claimed",cause:"Firm claiming deductions u/s 10AA or 80HH to 80RRB without computing Alternate Minimum Tax",resolution:"Compute AMT u/s 115JC if adjusted total income triggers liability. AMT applies to non-corporate assessees claiming specified deductions at 18.5% of adjusted total income."}],o={formId:e,fyApplicable:t,redFlags:i,validationErrors:r};export{o as default,e as formId,t as fyApplicable,i as redFlags,r as validationErrors};
